python3 -c "
import json
# Key topics for Jan 14
topics = {
    'AFCON SF': ['AFCON', 'semifinal', 'Morocco', 'Nigeria', 'Senegal', 'Egypt'],
    'Australian Open': ['Australian Open', 'draw', 'Sinner', 'Alcaraz'],
    'NFL': ['NFL', 'Divisional', 'Seahawks', 'Bears', 'Rams', '49ers', 'Broncos', 'Patriots', 'Bills', 'Texans'],
    'Oscar': ['Oscar', 'Academy Award', 'nomination'],
    'Grammy': ['Grammy'],
    'TikTok': ['TikTok'],
    'Champions League': ['Champions League', 'UCL'],
}
counts = {}
with open('articles/2026/01/14/articles.jsonl') as f:
    for line in f:
        a = json.loads(line)
        title = a.get('title','') or ''
        for topic, kws in topics.items():
            for kw in kws:
                if kw.lower() in title.lower():
                    counts[topic] = counts.get(topic, 0) + 1
                    break
for topic, count in sorted(counts.items(), key=lambda x: -x[1]):
    print(f'{topic}: {count}')
"
